</pre> result Out[5]: <pre>ToolCallResult(tool_call_id='77148f15-74d5-4b38-9e9f-d39620bb7031', content={'search_results': {'hits': [{'data': '...'}]}}, error=False)</pre> In [6]: Copied! <pre>from typing import Any

from llm_agents_from_scratch.base.tool import BaseTool
from llm_agents_from_scratch.data_structures.tool import (
    ToolCall,
    ToolCallResult,
)


class Hailstone(BaseTool):  # A
    @property
    def name(self) -&gt; str:
        return "hailstone"

    @property
    def description(self) -&gt; str:
        return "A tool that performs a Hailstone step on a given input number."

    @property
    def parameters_json_schema(self) -&gt; dict[str, Any]:
        """JSON Schema for tool parameters."""
        return {
            "type": "object",
            "properties": {
                "x": {
                    "type": "number",
                    "description": "The input number.",
                },
            },
            "required": ["x"],
        }

    def __call__(
        self,
        tool_call: ToolCall,
        *args: Any,
        **kwargs: Any,
    ) -&gt; ToolCallResult:
        """Execute the tool call."""
        x = tool_call.arguments.get("x")
        if x % 2 == 0:
            result = x // 2
        else:
            result = (x * 3) + 1

        return ToolCallResult(
            tool_call_id=tool_call.id_,
            content=result,
            error=False,
        )
